script:
frappe.listview_settings['Buyback Price Master'] = {
    onload(listview) {
        if (listview._ch_info_added) return;
        listview._ch_info_added = true;

        listview.page.add_inner_button('Open Ready Reckoner', () => {
            frappe.set_route('ch-ready-reckoner');
        });

        listview.page.set_indicator('Read Only', 'blue');
    }
};

frappe.ui.form.on('Buyback Price Master', {
    refresh(frm) {
        render_price_grid(frm);
    }
});

function render_price_grid(frm) {
    if (frm.is_new()) return;

    const fmt = (v) => {
        v = flt(v);
        if (!v) return '<span style="color:#ccc">—</span>';
        return format_currency(v, frm.doc.currency || 'INR');
    };

    const periods = [
        { label: 'IW 0–3 Mo',  suffix: 'In Warranty',     grades: ['a_grade_iw_0_3','b_grade_iw_0_3','c_grade_iw_0_3',''] },
        { label: 'IW 0–6 Mo',  suffix: 'In Warranty',     grades: ['a_grade_iw_0_6','b_grade_iw_0_6','c_grade_iw_0_6','d_grade_iw_0_6'] },
        { label: 'IW 6–11 Mo', suffix: 'In Warranty',     grades: ['a_grade_iw_6_11','b_grade_iw_6_11','c_grade_iw_6_11','d_grade_iw_6_11'] },
        { label: 'OOW 11+ Mo',     suffix: 'Out of Warranty', grades: ['a_grade_oow_11','b_grade_oow_11','c_grade_oow_11','d_grade_oow_11'] }
    ];

    let rows = '';
    for (let i = 0; i < periods.length; i++) {
        let p = periods[i];
        let bg = i % 2 === 0 ? '#fff' : '#f8fafb';
        rows += `<tr style="background:${bg}">`;
        rows += `<td style="padding:10px 14px;font-weight:500;color:#333;border-bottom:1px solid #eee">${p.label}</td>`;
        for (let g of p.grades) {
            let val = g ? fmt(frm.doc[g]) : '';
            rows += `<td style="text-align:right;padding:10px 14px;border-bottom:1px solid #eee;color:#36414C">${val}</td>`;
        }
        rows += '</tr>';
    }

    const html = `
    <div style="display:flex;gap:16px;margin-bottom:16px">
        <div style="flex:1;background:linear-gradient(135deg,#667eea 0%,#764ba2 100%);border-radius:10px;padding:18px 20px;color:#fff">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:0.5px;opacity:0.85;margin-bottom:4px">Market Price</div>
            <div style="font-size:22px;font-weight:700">${fmt(frm.doc.current_market_price)}</div>
        </div>
        <div style="flex:1;background:linear-gradient(135deg,#11998e 0%,#38ef7d 100%);border-radius:10px;padding:18px 20px;color:#fff">
            <div style="font-size:11px;text-transform:uppercase;letter-spacing:0.5px;opacity:0.85;margin-bottom:4px">Vendor Price</div>
            <div style="font-size:22px;font-weight:700">${fmt(frm.doc.vendor_price)}</div>
        </div>
    </div>
    <div style="border:1px solid #e2e6ea;border-radius:8px;overflow:hidden">
        <table style="width:100%;border-collapse:collapse;font-size:13px">
            <thead><tr style="background:#f1f3f5">
                <th style="padding:10px 14px;text-align:left;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Warranty Period</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade A</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade B</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade C</th>
                <th style="padding:10px 14px;text-align:right;font-weight:600;color:#555;border-bottom:2px solid #dee2e6">Grade D</th>
            </tr></thead>
            <tbody>${rows}</tbody>
        </table>
    </div>`;

    frm.fields_dict.price_grid_html.$wrapper.html(html);
}
